import{_ as t,o as a,c as s,ae as i}from"./chunks/framework.BMBGeRFM.js";const u=JSON.parse('{"title":"A short break.","description":"","frontmatter":{"title":"A short break.","date":"2026-05-06T00:00:00.000Z"},"headers":[],"relativePath":"news/2026-05-06-a-break.md","filePath":"news/2026-05-06-a-break.md"}'),n={name:"news/2026-05-06-a-break.md"};function r(h,e,o,p,l,k){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="i-m-taking-a-short-break" tabindex="-1">I&#39;m Taking A Short Break. <a class="header-anchor" href="#i-m-taking-a-short-break" aria-label="Permalink to &quot;I&#39;m Taking A Short Break.&quot;">​</a></h1><hr><p>It&#39;s been around 2 months, more or less since I started developing Farben, the terminal coloring crate that uses markup.</p><p>The latest update, as of writing this is <a href="https://crates.io/crates/farben/0.18.1" target="_blank" rel="noreferrer">0.18.1</a> and the latest (unreleased, git-only) Alpha being 0.19 Alpha 5, just released after this paper.</p><p>Even then, I haven&#39;t really updated Farben that much after 0.18, other than a couple of fun commits for experimental features for the 0.19 update. The 0.19 update, other than adding new features, is an update that focuses on community responses, primarily through the <a href="https://github.com/razkar-studio/farben/issues" target="_blank" rel="noreferrer">GitHub Issues</a> of the repository.</p><p>I am announcing that I&#39;ll be taking an extremely short break added on to the already pending delay after 0.18.1, around 1-2 months.</p><hr><p>Other than being the sole maintainer of Farben, I also make other projects too and experiment with the beautiful Rust language. Check them out if you haven&#39;t.</p><p>The actual reason is the education system (it always is). My school&#39;s final exam of the year is coming up and I need to lock in on this one more than Farben.</p><p>That being said, once the break is complete, I promise to deliver the update and a bunch more improvements to Farben. I hope that Farben will be the coloring library for you.</p><p>A sneak peek of the next updates:</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/i wonder what this is/ *or this* _or this_ ~we get it~ `you should know by now`&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[link(https://example.com/)] &lt;- What&#39;s that supposed to be? Hmm.. [/link]&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lossy!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[rgb(200, 14, 24)]All will be polished, detected, safe, and hopefully performant.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span></code></pre></div><hr><p>If you have any suggestions, bug reports, or anything, please, and I say this deeply, please submit a <a href="https://github.com/razkar-studio/farben/issues" target="_blank" rel="noreferrer">GitHub Issue</a>. I&#39;m trying my best to make Farben at the best of its state, and keep making it better by the day. An issue wouldn&#39;t hurt, and I usually respond pretty quickly (other than the whole break thing).</p><p>Thank you for reading this announcement, checking out Farben, using it, starring it (please do), and lovin&#39; it!</p><p>Make great things with Farben.</p><p>Cheers, RazkarStudio.</p>',17)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
